using System.Net.Http;
using System.Text.Json;

public class StripeClient
{
    private readonly HttpClient _http;
    private readonly string _apiKey;

    public StripeClient(string apiKey)
    {
        _apiKey = apiKey;
        _http = new HttpClient();
        _http.DefaultRequestHeaders.Add("Authorization", $"Bearer {_apiKey}");
    }

    public async Task<Charge> CreateCharge(int amount, string currency)
    {
        var response = await _http.PostAsync("https://api.stripe.com/v1/charges", null);
        return JsonSerializer.Deserialize<Charge>(await response.Content.ReadAsStringAsync())!;
    }
}

